from dataclasses import dataclass
from typing import Union, Optional
import re


@dataclass
class ASTNode:
    type: str
    value: Optional[float] = None
    op: Optional[str] = None
    left: Optional["ASTNode"] = None
    right: Optional["ASTNode"] = None
    operand: Optional["ASTNode"] = None


class Tokenizer:
    def __init__(self, expression: str):
        self.expression = expression
        self.pos = 0
        self.tokens = self._tokenize()
        self.token_pos = 0

    def _tokenize(self) -> list:
        tokens = []
        i = 0
        expr = self.expression.replace(" ", "")

        while i < len(expr):
            ch = expr[i]

            if ch.isdigit() or ch == ".":
                j = i
                has_dot = ch == "."
                while j + 1 < len(expr) and (
                    expr[j + 1].isdigit() or (expr[j + 1] == "." and not has_dot)
                ):
                    j += 1
                    if expr[j] == ".":
                        has_dot = True
                num_str = expr[i : j + 1]
                if num_str == ".":
                    raise ValueError(f"Invalid token at position {i}")
                try:
                    tokens.append(("NUMBER", float(num_str)))
                except ValueError:
                    raise ValueError(f"Invalid number at position {i}")
                i = j + 1
            elif ch in "+-*/":
                tokens.append(("OP", ch))
                i += 1
            elif ch == "(":
                tokens.append(("LPAREN", "("))
                i += 1
            elif ch == ")":
                tokens.append(("RPAREN", ")"))
                i += 1
            else:
                raise ValueError(f"Invalid character '{ch}' at position {i}")

        return tokens

    def peek(self) -> Optional[tuple]:
        if self.token_pos < len(self.tokens):
            return self.tokens[self.token_pos]
        return None

    def consume(self) -> tuple:
        token = self.peek()
        if token is None:
            raise ValueError("Unexpected end of expression")
        self.token_pos += 1
        return token

    def expect(self, token_type: str) -> tuple:
        token = self.consume()
        if token[0] != token_type:
            raise ValueError(f"Expected {token_type}, got {token[0]}")
        return token


class Parser:
    def __init__(self, tokenizer: Tokenizer):
        self.tokenizer = tokenizer

    def parse(self) -> ASTNode:
        if not self.tokenizer.tokens:
            raise ValueError("Empty expression")

        result = self._expression()

        if self.tokenizer.peek() is not None:
            raise ValueError("Unexpected token after expression")

        return result

    def _expression(self) -> ASTNode:
        return self._additive()

    def _additive(self) -> ASTNode:
        left = self._multiplicative()

        while True:
            token = self.tokenizer.peek()
            if token and token[0] == "OP" and token[1] in "+-":
                op_token = self.tokenizer.consume()
                right = self._multiplicative()
                left = ASTNode(type="binop", op=op_token[1], left=left, right=right)
            else:
