    def _multiplicative(self) -> ASTNode:
        left = self._unary()

        while True:
            token = self.tokenizer.peek()
            if token and token[0] == "OP" and token[1] in "*/":
                op_token = self.tokenizer.consume()
                right = self._unary()
                left = ASTNode(type="binop", op=op_token[1], left=left, right=right)
            else:
                break

        return left

    def _unary(self) -> ASTNode:
        token = self.tokenizer.peek()
