    if not expression or not expression.strip():
        raise ValueError("Empty expression")

    tokenizer = Tokenizer(expression)
    parser = Parser(tokenizer)
    return parser.parse()


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        if node.value is None:
            raise ValueError("Number node has no value")
        return node.value

    if node.type == "unary":
        if node.operand is None:
            raise ValueError("Unary node has no operand")
        if node.op == "-":
            return -evaluate(node.operand)
        raise ValueError(f"Unknown unary operator: {node.op}")

    if node.type == "binop":
        if node.left is None or node.right is None:
            raise ValueError("Binary operator node missing operands")
        if node.op is None:
            raise ValueError("Binary operator node has no operator")

        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
        else:
            raise ValueError(f"Unknown operator: {node.op}")

    raise ValueError(f"Unknown node type: {node.type}")


if __name__ == "__main__":
    test_cases = [
        "2 + 3",
        "10 - 4",
        "3 * 4",
        "15 / 3",
        "2 + 3 * 4",
        "(2 + 3) * 4",
        "-5",
        "-(3 + 2)",
        "2 * -3",
        "10 / (2 + 3)",
        "1 + 2 + 3 + 4",
        "((2 + 3) * (4 - 1)) / 5",
    ]

    print("Expression Parser Tests")
    print("=" * 50)

    for expr in test_cases:
        try:
            ast = parse(expr)
            result = evaluate(ast)
            print(f"{expr:25} = {result}")
        except Exception as e:
            print(f"{expr:25} -> Error: {e}")

    print("\nError Cases:")
    print("=" * 50)

    error_cases = [
        "",
        "2 +",
        "(2 + 3",
        "2 + 3)",
        "2 @ 3",
    ]

    for expr in error_cases:
        try:
            parse(expr)
            print(f"{repr(expr):25} -> No error (unexpected)")
        except ValueError as e:
            print(f"{repr(expr):25} -> ValueError: {e}")
        except Exception as e:
            print(f"{repr(expr):25} -> {type(e).__name__}: {e}")

    print("\nDivision by Zero:")
    print("=" * 50)
    try:
        ast = parse("10 / 0")
        evaluate(ast)
        print("10 / 0                   -> No error (unexpected)")
    except ZeroDivisionError as e:
        print(f"10 / 0                   -> ZeroDivisionError: {e}")
